mapper.select:
select * from (select ROW_NUMBER() OVER(ORDER BY b.bno desc) as rw, b.*
from board_view b) bv
where ceil(bv.rw/${size}) = ${page}

select * from (select ROW_NUMBER() OVER(ORDER BY b.bno desc) as rw, b.*
from board_view b where b.title concat('%',${keyword},'%') OR b.content concat('%',${keyword},'%')) bv
where ceil(bv.rw/${size}) = ${page}
